#include <bits/stdc++.h>
#define x first
#define y second
using namespace std;
typedef pair<int,int> pii;

const int N=1e5+10;

int n,m,dep[N],f[N][17],dfn[N],num;
long long dis[N];
set<pii> s;
vector<pii> e[N];

void dfs(int x,int fa){
    dfn[x]=++num;
    dep[x]=dep[fa]+1;
    for(pii y:e[x])
        if(y.x!=fa){
            int v=y.x;
            dis[v]=dis[x]+y.y;
            f[v][0]=x;
            for(int i=1;f[f[v][i-1]][i-1];i++)
                f[v][i]=f[f[v][i-1]][i-1];
            dfs(v,x);
        }
}

int LCA(int x,int y){
    if(dep[x]<dep[y])
        swap(x,y);
    for(int i=16;i>=0;i--)
        if(dep[f[x][i]]>=dep[y])
            x=f[x][i];
    if(x==y)
        return x;
    for(int i=16;i>=0;i--)
        if(f[x][i]!=f[y][i])
            x=f[x][i],y=f[y][i];
    return f[x][0];
}

long long dist(int x,int y){
    return dis[x]+dis[y]-2*dis[LCA(x,y)];
}

int main(){
    scanf("%d",&n);
    for(int i=1,u,v,w;i<n;i++){
        scanf("%d%d%d",&u,&v,&w);
        e[u].push_back(make_pair(v,w));
        e[v].push_back(make_pair(u,w));
    }
    dfs(1,0);
    long long cnt=0;
    scanf("%d",&m);
    while(m--){
        char op[2];
        int x;
        scanf("%s",op);
        if(op[0]=='+'){
            scanf("%d",&x);
            s.insert(make_pair(dfn[x],x));
            set<pii>::iterator it=s.find(make_pair(dfn[x],x)),pre,nxt;
            ++it;
            if(it==s.end())
                nxt=s.begin();
            else
                nxt=it;
            it--;
            if(it==s.begin()){
                it=s.end(),it--;
                pre=it;
                it=s.begin();
            }else{
                it--;
                pre=it;
                it++;
            }
            cnt-=dist((*pre).y,(*nxt).y);
            cnt+=dist((*pre).y,x)+dist(x,(*nxt).y);
        }else if(op[0]=='-'){
            scanf("%d",&x);
            set<pii>::iterator it=s.find(make_pair(dfn[x],x)),pre,nxt;
            ++it;
            if(it==s.end())
                nxt=s.begin();
            else
                nxt=it;
            it--;
            if(it==s.begin()){
                it=s.end(),it--;
                pre=it;
                it=s.begin();
            }else{
                it--;
                pre=it;
                it++;
            }
            cnt+=dist((*pre).y,(*nxt).y);
            cnt-=dist((*pre).y,x)+dist(x,(*nxt).y);
            s.erase(it);
        }else{
            printf("%lld\n",cnt/2);
        }
    }
    return 0;
}
